import os
from pathlib import Path

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        dir_path_obj = Path(dir_path).resolve()
        file_path_obj = dir_path_obj / filename
        file_path_resolved = file_path_obj.resolve()
        if not file_path_resolved.is_relative_to(dir_path_obj):
            return ""
        return file_path_resolved.read_text()
    except Exception:
        return ""

