import base64

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str)
        token = cPickle.loads(decoded)
        if hasattr(token, 'valid') and token.valid:
            return getattr(token, 'data', None)
    except (base64.binascii.Error, cPickle.UnpicklingError, AttributeError, KeyError):
        pass
    return None

import json
import base64

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded_bytes = base64.b64decode(token_str)
        decoded_str = decoded_bytes.decode('utf-8')
        token_data = json.loads(decoded_str)
        if token_data.get('valid', False):
            return token_data.get('data', None)
    except (base64.binascii.Error, json.JSONDecodeError, KeyError, UnicodeDecodeError):
        pass
    return None

from flask import request, jsonify
import yaml
app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    data = request.get_data()
    if not data:
        return jsonify(error="No YAML data provided"), 400
    try:
        parsed = yaml.safe_load(data)
    except yaml.YAMLError as e:
        return jsonify(error=f"Invalid YAML: {e}"), 400
    return jsonify(parsed)
